import{_ as t,o as a,c as o,ag as i}from"./chunks/framework.Vng7Hdlh.js";const u=JSON.parse('{"title":"Access Control (Door Management)","description":"","frontmatter":{},"headers":[],"relativePath":"admin-ui/access-control.md","filePath":"admin-ui/access-control.md"}'),s={name:"admin-ui/access-control.md"};function d(n,e,r,l,c,p){return a(),o("div",null,[...e[0]||(e[0]=[i(`<h1 id="access-control-door-management" tabindex="-1">Access Control (Door Management) <a class="header-anchor" href="#access-control-door-management" aria-label="Permalink to &quot;Access Control (Door Management)&quot;">​</a></h1><p>Physical access control integration for healthcare facilities. Proxy Smart provides a vendor-agnostic abstraction over door access systems, with built-in Keycloak user sync and group-based authorization.</p><h2 id="supported-providers" tabindex="-1">Supported Providers <a class="header-anchor" href="#supported-providers" aria-label="Permalink to &quot;Supported Providers&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Provider</th><th>Type</th><th>Capabilities</th></tr></thead><tbody><tr><td><strong>Kisi</strong></td><td>Cloud API</td><td>Locations, Doors, Groups, Members, Events, Sync, Unlock</td></tr><tr><td><strong>UniFi Access</strong></td><td>Local Controller</td><td>Locations (floors), Doors, Groups*, Members*, Events*, Sync*, Unlock, Real-time WS</td></tr></tbody></table><p>* UniFi groups/members/sync are managed by Proxy Smart (persisted in local state) since UniFi Access doesn&#39;t have a native user/group API.</p><h2 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h2><h3 id="environment-variables" tabindex="-1">Environment Variables <a class="header-anchor" href="#environment-variables" aria-label="Permalink to &quot;Environment Variables&quot;">​</a></h3><h4 id="kisi" tabindex="-1">Kisi <a class="header-anchor" href="#kisi" aria-label="Permalink to &quot;Kisi&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Variable</th><th>Required</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>KISI_API_KEY</code></td><td>Yes</td><td>—</td><td>API key from your Kisi dashboard</td></tr><tr><td><code>KISI_BASE_URL</code></td><td>No</td><td><code>https://api.kisi.io</code></td><td>Override for self-hosted Kisi</td></tr><tr><td><code>KISI_TIMEOUT_MS</code></td><td>No</td><td><code>10000</code></td><td>HTTP request timeout</td></tr></tbody></table><h4 id="unifi-access" tabindex="-1">UniFi Access <a class="header-anchor" href="#unifi-access" aria-label="Permalink to &quot;UniFi Access&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Variable</th><th>Required</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>UNIFI_ACCESS_HOST</code></td><td>Yes</td><td>—</td><td>Controller IP or FQDN (no protocol)</td></tr><tr><td><code>UNIFI_ACCESS_USERNAME</code></td><td>Yes</td><td>—</td><td>Controller admin username</td></tr><tr><td><code>UNIFI_ACCESS_PASSWORD</code></td><td>Yes</td><td>—</td><td>Controller admin password</td></tr></tbody></table><h4 id="provider-selection" tabindex="-1">Provider Selection <a class="header-anchor" href="#provider-selection" aria-label="Permalink to &quot;Provider Selection&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Variable</th><th>Description</th></tr></thead><tbody><tr><td><code>ACCESS_CONTROL_PROVIDER</code></td><td>Force <code>kisi</code> or <code>unifi-access</code>. Auto-detected if omitted.</td></tr></tbody></table><p>Auto-detection priority: if <code>KISI_API_KEY</code> is set, Kisi is used. Otherwise if <code>UNIFI_ACCESS_HOST</code> is set, UniFi Access is used.</p><h3 id="in-app-configuration" tabindex="-1">In-App Configuration <a class="header-anchor" href="#in-app-configuration" aria-label="Permalink to &quot;In-App Configuration&quot;">​</a></h3><p>The <strong>Configure Provider</strong> panel in the UI allows setting up access control without editing environment variables:</p><ol><li>Select provider type (Kisi or UniFi Access)</li><li>Enter credentials</li><li><strong>Test Connection</strong> — validates connectivity before saving</li><li><strong>Save</strong> — writes config to <code>.env</code> and reinitializes the provider</li></ol><h2 id="admin-ui" tabindex="-1">Admin UI <a class="header-anchor" href="#admin-ui" aria-label="Permalink to &quot;Admin UI&quot;">​</a></h2><p>The Door Management page is a tabbed interface. Tabs are shown or hidden based on the active provider&#39;s capabilities.</p><h3 id="overview-tab" tabindex="-1">Overview Tab <a class="header-anchor" href="#overview-tab" aria-label="Permalink to &quot;Overview Tab&quot;">​</a></h3><ul><li>Stat cards: location count, door count, group count, member count</li><li>Door status grid showing online/offline state per door</li><li>Locations list with addresses</li></ul><h3 id="doors-tab" tabindex="-1">Doors Tab <a class="header-anchor" href="#doors-tab" aria-label="Permalink to &quot;Doors Tab&quot;">​</a></h3><ul><li>Searchable door list, grouped by location</li><li>Per-door badges: online/offline, locked/unlocked</li><li><strong>Unlock</strong> button per door (with loading/success/error feedback)</li></ul><h3 id="groups-tab-capability-gated" tabindex="-1">Groups Tab <em>(capability-gated)</em> <a class="header-anchor" href="#groups-tab-capability-gated" aria-label="Permalink to &quot;Groups Tab *(capability-gated)*&quot;">​</a></h3><ul><li>Create and delete access groups</li><li>Expand a group to view and manage its door assignments</li><li>Assign or remove doors from groups</li></ul><h3 id="members-tab-capability-gated" tabindex="-1">Members Tab <em>(capability-gated)</em> <a class="header-anchor" href="#members-tab-capability-gated" aria-label="Permalink to &quot;Members Tab *(capability-gated)*&quot;">​</a></h3><ul><li>Create and delete members (by email)</li><li>View group memberships per member</li><li><strong>Sync from Keycloak</strong> button — imports users from the Keycloak realm</li></ul><h3 id="events-tab-capability-gated" tabindex="-1">Events Tab <em>(capability-gated)</em> <a class="header-anchor" href="#events-tab-capability-gated" aria-label="Permalink to &quot;Events Tab *(capability-gated)*&quot;">​</a></h3><ul><li>Paginated audit log of access events</li><li>Columns: action, actor, door, timestamp</li><li>Searchable by actor email, door, or action type</li></ul><h2 id="api-endpoints" tabindex="-1">API Endpoints <a class="header-anchor" href="#api-endpoints" aria-label="Permalink to &quot;API Endpoints&quot;">​</a></h2><p>All endpoints are under <code>/admin/access-control</code> and require a valid admin Bearer token.</p><h3 id="core-always-available" tabindex="-1">Core (always available) <a class="header-anchor" href="#core-always-available" aria-label="Permalink to &quot;Core (always available)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Method</th><th>Path</th><th>Description</th></tr></thead><tbody><tr><td><code>GET</code></td><td><code>/health</code></td><td>Provider health check + capability flags</td></tr><tr><td><code>GET</code></td><td><code>/overview</code></td><td>Combined stats (locations, doors, groups, members)</td></tr><tr><td><code>GET</code></td><td><code>/locations</code></td><td>List locations (paginated)</td></tr><tr><td><code>GET</code></td><td><code>/locations/:id</code></td><td>Get single location</td></tr><tr><td><code>GET</code></td><td><code>/doors</code></td><td>List doors (paginated)</td></tr><tr><td><code>GET</code></td><td><code>/doors/:id</code></td><td>Get single door</td></tr><tr><td><code>POST</code></td><td><code>/doors/:id/unlock</code></td><td>Unlock a door</td></tr><tr><td><code>GET</code></td><td><code>/events</code></td><td>List access events (paginated)</td></tr></tbody></table><h3 id="groups-optional" tabindex="-1">Groups (optional) <a class="header-anchor" href="#groups-optional" aria-label="Permalink to &quot;Groups (optional)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Method</th><th>Path</th><th>Description</th></tr></thead><tbody><tr><td><code>GET</code></td><td><code>/groups</code></td><td>List groups</td></tr><tr><td><code>GET</code></td><td><code>/groups/:id</code></td><td>Get single group</td></tr><tr><td><code>POST</code></td><td><code>/groups</code></td><td>Create group (<code>{ name, description? }</code>)</td></tr><tr><td><code>DELETE</code></td><td><code>/groups/:id</code></td><td>Delete group</td></tr><tr><td><code>GET</code></td><td><code>/group-doors</code></td><td>List group-door assignments</td></tr><tr><td><code>POST</code></td><td><code>/group-doors</code></td><td>Assign door to group (<code>{ groupId, doorId }</code>)</td></tr><tr><td><code>DELETE</code></td><td><code>/group-doors/:id</code></td><td>Remove door from group</td></tr></tbody></table><h3 id="members-optional" tabindex="-1">Members (optional) <a class="header-anchor" href="#members-optional" aria-label="Permalink to &quot;Members (optional)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Method</th><th>Path</th><th>Description</th></tr></thead><tbody><tr><td><code>GET</code></td><td><code>/members</code></td><td>List members</td></tr><tr><td><code>GET</code></td><td><code>/members/:id</code></td><td>Get single member</td></tr><tr><td><code>POST</code></td><td><code>/members</code></td><td>Create member (<code>{ email, name? }</code>)</td></tr><tr><td><code>DELETE</code></td><td><code>/members/:id</code></td><td>Delete member</td></tr></tbody></table><h3 id="sync-configuration" tabindex="-1">Sync &amp; Configuration <a class="header-anchor" href="#sync-configuration" aria-label="Permalink to &quot;Sync &amp; Configuration&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Method</th><th>Path</th><th>Description</th></tr></thead><tbody><tr><td><code>POST</code></td><td><code>/sync</code></td><td>Sync users from Keycloak (with optional role mappings)</td></tr><tr><td><code>GET</code></td><td><code>/config/status</code></td><td>Current provider configuration status</td></tr><tr><td><code>POST</code></td><td><code>/config/test</code></td><td>Test connection to a provider</td></tr><tr><td><code>POST</code></td><td><code>/config/configure</code></td><td>Save provider configuration</td></tr></tbody></table><p>Endpoints for optional capabilities return <strong>501 Not Implemented</strong> when the active provider doesn&#39;t support them.</p><h2 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌──────────────────┐</span></span>
<span class="line"><span>│   Admin UI       │</span></span>
<span class="line"><span>│  DoorManagement  │</span></span>
<span class="line"><span>└────────┬─────────┘</span></span>
<span class="line"><span>         │ REST API</span></span>
<span class="line"><span>         ▼</span></span>
<span class="line"><span>┌──────────────────┐</span></span>
<span class="line"><span>│  Access Control  │</span></span>
<span class="line"><span>│  Admin Routes    │  /admin/access-control/*</span></span>
<span class="line"><span>└────────┬─────────┘</span></span>
<span class="line"><span>         │</span></span>
<span class="line"><span>         ▼</span></span>
<span class="line"><span>┌──────────────────┐</span></span>
<span class="line"><span>│   Provider       │</span></span>
<span class="line"><span>│   Abstraction    │  AccessControlProvider interface</span></span>
<span class="line"><span>├────────┬─────────┤</span></span>
<span class="line"><span>│  Kisi  │  UniFi  │</span></span>
<span class="line"><span>│Provider│Provider  │</span></span>
<span class="line"><span>└────────┴─────────┘</span></span>
<span class="line"><span>         │</span></span>
<span class="line"><span>         ▼</span></span>
<span class="line"><span>┌──────────────────┐</span></span>
<span class="line"><span>│  External API    │</span></span>
<span class="line"><span>│  Kisi Cloud /    │</span></span>
<span class="line"><span>│  UniFi Controller│</span></span>
<span class="line"><span>└──────────────────┘</span></span></code></pre></div><h3 id="provider-interface" tabindex="-1">Provider Interface <a class="header-anchor" href="#provider-interface" aria-label="Permalink to &quot;Provider Interface&quot;">​</a></h3><p>The <code>AccessControlProvider</code> interface defines:</p><ul><li><strong>Required</strong>: <code>isHealthy()</code>, <code>getLocations()</code>, <code>getDoors()</code>, <code>unlock()</code></li><li><strong>Optional</strong>: <code>getGroups()</code>, <code>getMembers()</code>, <code>getEvents()</code>, <code>syncUsersFromKeycloak()</code>, <code>getOverview()</code></li><li><strong>Capabilities object</strong>: declares which optional methods are available</li></ul><p>Routes check capabilities at runtime and degrade gracefully (501) when a feature isn&#39;t supported.</p><h2 id="keycloak-sync" tabindex="-1">Keycloak Sync <a class="header-anchor" href="#keycloak-sync" aria-label="Permalink to &quot;Keycloak Sync&quot;">​</a></h2><p>The sync flow:</p><ol><li>Admin clicks <strong>Sync from Keycloak</strong> (or calls <code>POST /sync</code>)</li><li>Backend fetches all users from the Keycloak realm</li><li>For each user, checks realm-role mappings against optional <code>roleMappings</code> rules</li><li>Creates new members in the access control provider (skips existing)</li><li>Assigns groups based on role mapping matches</li><li>Returns a summary: <code>{ created[], skipped[], failed[] }</code></li></ol><h3 id="role-mapping-rules" tabindex="-1">Role Mapping Rules <a class="header-anchor" href="#role-mapping-rules" aria-label="Permalink to &quot;Role Mapping Rules&quot;">​</a></h3><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;roleMappings&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    { </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;keycloakRole&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;doctor&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;groupId&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;grp-1&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    { </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;keycloakRole&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;nurse&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;groupId&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;grp-2&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  ]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>Role matching is case-insensitive and uses substring matching (e.g., <code>&quot;doctor&quot;</code> matches role <code>&quot;senior-doctor&quot;</code>).</p><h2 id="unifi-access-unlock-authorization" tabindex="-1">UniFi Access: Unlock Authorization <a class="header-anchor" href="#unifi-access-unlock-authorization" aria-label="Permalink to &quot;UniFi Access: Unlock Authorization&quot;">​</a></h2><p>For UniFi Access, the provider implements group-based unlock authorization:</p><ol><li>Request comes in to unlock door X</li><li>Provider checks if the requesting user&#39;s email is a member</li><li>Checks if the member belongs to a group that has door X assigned</li><li>Records a decision event (<code>unlock_allow</code> or <code>unlock_deny</code>) for audit</li><li>Proceeds with unlock only if authorized</li></ol><p>Decision events are persisted in the provider&#39;s local state file (<code>logs/access-control/unifi-provider-state.json</code>).</p>`,56)])])}const b=t(s,[["render",d]]);export{u as __pageData,b as default};
